// ──────────────────────────────────────────────────────────────────────────────
// BUILD-049 — Mock Provider (fully executable, deterministic)
// ──────────────────────────────────────────────────────────────────────────────
import crypto from "crypto";
import { BaseSDKProvider } from "../../provider-runtime/provider";
const ALL_CAPS = [
    "analyze", "create", "modify", "refactor", "delete",
    "validate", "document", "test", "cleanup"
];
export class MockSDKProvider extends BaseSDKProvider {
    id = "mock-sdk-provider";
    name = "Mock SDK Provider";
    metadata() {
        return {
            id: this.id,
            displayName: this.name,
            version: "1.0.0",
            vendor: "Project Brain",
            priority: 0,
            supportedCapabilities: ALL_CAPS,
            supportedLanguages: ["typescript", "javascript", "python", "go", "rust"],
            supportedModels: ["mock-model-v1", "mock-model-v2"],
            defaultModel: "mock-model-v1",
            supportsStreaming: true,
            supportsSessions: true,
            supportsCancellation: true,
            supportsPauseResume: true,
            runtimeCompatibility: "1.0.0"
        };
    }
    profile() {
        return {
            metadata: this.metadata(),
            limits: {
                maxContextTokens: 200_000,
                maxOutputTokens: 8_000,
                maxParallelTasks: 4,
                supportsStreaming: true,
                supportsImages: false,
                supportsTools: true,
                supportsSessions: true,
                supportsCancellation: true
            },
            pricing: {
                promptTokenCostPer1k: 0,
                completionTokenCostPer1k: 0,
                currency: "USD"
            }
        };
    }
    async execute(task, context, onEvent, onStream) {
        const startTime = Date.now();
        if (context.simulateFailure) {
            throw Object.assign(new Error("Simulated failure"), { retryable: false });
        }
        onEvent({ type: "TaskStarted", taskId: task.id, timestamp: new Date().toISOString(), payload: {} });
        if (onStream) {
            onStream({ type: "Status", taskId: task.id, timestamp: new Date().toISOString(), status: "Executing" });
            onStream({ type: "Token", taskId: task.id, timestamp: new Date().toISOString(), token: "// Generated by Mock SDK Provider\n" });
            onStream({ type: "Progress", taskId: task.id, timestamp: new Date().toISOString(), progress: 50 });
        }
        const checksum = crypto
            .createHash("sha256")
            .update(`${task.id}-${task.type}-${task.title}`)
            .digest("hex");
        const artifact = {
            id: `art-${checksum.slice(0, 8)}`,
            taskId: task.id,
            type: this.artifactType(task.type),
            path: task.file,
            content: this.generateContent(task),
            metadata: { provider: this.id, model: "mock-model-v1", deterministic: true },
            version: "1",
            createdAt: new Date().toISOString(),
            provider: this.id,
            checksum
        };
        if (onStream) {
            onStream({ type: "Artifact", taskId: task.id, timestamp: new Date().toISOString(), artifactId: artifact.id });
            onStream({ type: "Completed", taskId: task.id, timestamp: new Date().toISOString() });
        }
        onEvent({ type: "TaskCompleted", taskId: task.id, timestamp: new Date().toISOString(), payload: {} });
        const execTime = Date.now() - startTime;
        return {
            taskId: task.id,
            status: "Completed",
            artifacts: [artifact],
            metrics: {
                provider: this.id,
                capability: task.type,
                executionTime: execTime,
                retries: 0,
                artifactsProduced: 1,
                eventsEmitted: 2,
                taskCount: 1,
                cancellationCount: 0,
                pauseCount: 0,
                resumeCount: 0
            }
        };
    }
    artifactType(capability) {
        switch (capability) {
            case "test": return "test";
            case "document": return "documentation";
            case "validate": return "diagnostic";
            case "analyze": return "diagnostic";
            default: return "code";
        }
    }
    generateContent(task) {
        return [
            `// Task: ${task.title}`,
            `// Type: ${task.type}`,
            `// Provider: ${this.id}`,
            `// Deterministic output for task ${task.id}`,
            ``,
            `export function ${task.type}Task() {`,
            `    // Implementation generated by ${this.name}`,
            `    return { taskId: "${task.id}", status: "completed" };`,
            `}`,
        ].join("\n");
    }
}
